}];

const response = $input.first().json;
const ctx = $('[fix] Gemini 프롬프트 준비').first().json;

if (!response.candidates || response.candidates.length === 0) {
  return [{ json: { noChanges: true, geminiError: JSON.stringify(response.promptFeedback || response.error || 'no candidates'), ...ctx } }];
}

const candidate = response.candidates[0];
if (!candidate.content || !candidate.content.parts || candidate.finishReason === 'MALFORMED_FUNCTION_CALL') {
  return [{ json: { noChanges: true, geminiError: candidate.finishReason || 'no content', ...ctx } }];
}

const parts = candidate.content.parts;
const functionCalls = parts.filter(p => p.functionCall && p.functionCall.name === 'write_file');

if (functionCalls.length === 0) {
  return [{ json: { noChanges: true, ...ctx } }];
}

const fixedFiles = functionCalls.map(p => {
  const original = (ctx.allFiles || []).find(f => f.path === p.functionCall.args.path);
  return {
    path: p.functionCall.args.path,
    content: p.functionCall.args.content,
    description: p.functionCall.args.description,
    sha: original?.sha || null
  };
});

const filesSummary = fixedFiles.map(f => `• \`${f.path}\`: ${f.description}`).join('\n');

return [{
  json: {
    noChanges: false,
    ...ctx,
    fixedFiles,
    filesSummary
  }
}];

const data = $input.first().json;
if (data.noChanges || !data.fixedFiles || data.fixedFiles.length === 0) return [];
const fixedFiles = data.fixedFiles.filter(f => f.path && f.content && f.content.trim().length > 0);
if (fixedFiles.length === 0) return [];
const { headBranch, repoOwner, repoName, filesSummary } = data;
const token = $env.GITHUB_TOKEN;
const baseUrl = `https://api.github.com/repos/${repoOwner}/${repoName}`;

const headers = {
  'Authorization': `Bearer ${token}`,
  'Accept': 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
  'Content-Type': 'application/json',
  'User-Agent': 'n8n-jump-section'
};

function request(method, url, body) {
  return new Promise((resolve, reject) => {
    const https = require('https');
    const path = url.replace('https://api.github.com', '');
    const options = { hostname: 'api.github.com', path, method, headers };
    const req = https.request(options, (res) => {
      let d = '';
      res.on('data', chunk => d += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) reject(new Error(`HTTP ${res.statusCode}: ${d}`));
        else resolve(JSON.parse(d));
      });
    });
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('Request timeout')); });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

const refData = await request('GET', `${baseUrl}/git/refs/heads/${headBranch}`);
const baseSha = refData.object.sha;
const commitData = await request('GET', `${baseUrl}/git/commits/${baseSha}`);
const baseTreeSha = commitData.tree.sha;

const newTree = await request('POST', `${baseUrl}/git/trees`, {
  base_tree: baseTreeSha,
  tree: fixedFiles.map(f => ({ path: f.path, mode: '100644', type: 'blob', content: f.content }))
});

const newCommit = await request('POST', `${baseUrl}/git/commits`, {
  message: `fix: apply review comment suggestion\n\n${filesSummary}`,
  tree: newTree.sha,
  parents: [baseSha]
});

await request('PATCH', `${baseUrl}/git/refs/heads/${headBranch}`, { sha: newCommit.sha });

return [{ json: { ...data, commitSha: newCommit.sha } }];
